head.script:
scwin.userClsCd = $c.data.getMemInfo("userClsCd");	// 사용자 구분코드
scwin.loginClntNo = $c.data.getMemInfo("clntNo");
scwin.loginClntNm = $c.data.getMemInfo("clntNm");
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd");

scwin.dateStr = $c.date.getServerDateTime("yyyyMMdd"); //현재일자
scwin.searchFlag = 0;
//scwin.isPreceding = false;// 전일 등록 차량 불러오기

//-------------------------------------------------------------------------
// 페이지로드
//-------------------------------------------------------------------------
scwin.onpageload = function () {

    //-----------------------------------------------------------------------------
    // 사용자가 협력업체일경우 거래처에 협력업체 셋팅 후 입력 불가능하게 한다.
    //-----------------------------------------------------------------------------
    if (scwin.userClsCd != "01") { //사용자가 협력업체 일때
        ed_clntNo.setValue(scwin.loginClntNo);
        ed_clntNm.setValue(scwin.loginClntNm);

        $c.gus.cfDisableObjects([ed_clntNo, ed_clntNm, btn_clntNo]);
    }

    const codeOptions = [
        { grpCd: "OP190", compID: "acb_con_cargoClsCd,gr_subWorkImplement:cargoClsCd" } //가용차량등록 그리드 : 화물구분
    ];
    $c.data.setCommonCode(codeOptions);

    //-------------------------------------------------------------------------
    // 사용자의 상위물류점소코드 계약점소에 셋팅(그리드 점소 추가해야 함!!)
    //-------------------------------------------------------------------------
    const codeOptions2 = [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            compID: "acb_con_logisticsBranch"
        },
        {
            method: "getGridCombo",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            compID: "gr_subWorkImplement:lobranCd"
        }
    ];

    $c.data.setGauceUtil(codeOptions2, function () {
        const list = dlt_gauceUtil_gr_subWorkImplement_lobranCd.getAllJSON();
        dlt_gauceUtil_gr_subWorkImplement_lobranCd.setJSON(list.map(item => ({
            ...item, 
            name: item.name.replace(/^\[.*?\]/, "") 
        })));
        if (scwin.loUpperLobranCd) {
            acb_con_logisticsBranch.setValue(scwin.loUpperLobranCd);
        }
    });

    //가용차량등록 그리드 - 샤시종류 콤보박스 조회
    scwin.f_RetrieveChassis();

    //화종구분1
    //ds_whajong1.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=EquipmentNonUsableEBC&queryId=retriveKcgClsCdCombo&param1=1";
    //ds_whajong1.Reset();

    //화종구분2
    //ds_whajong2.DataID = "/cm.zz.RetrieveComboCMD.do?sysCd=EquipmentNonUsableEBC&queryId=retriveKcgClsCdCombo&param1=1";
    //ds_whajong2.Reset();

    //가용차량등록 그리드 - 복화권역 콤보박스 조회
    scwin.f_RetrieveArea();
};

//-------------------------------------------------------------------------
// UDC Completed
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $p.setTimeout(function () {
        //소스
        ica_con_usblDt.setValue(scwin.dateStr);

        //테스트 데이터        
        // ds_queryCondition.set("clntNo", "101343");
        // ds_queryCondition.set("lobranCd", "6AA");

    }, { "delay": 50 });
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    scwin.searchFlag = 0;

    let ret = await $c.gus.cfValidate([tbl_searchCond]);
    if (!ret) {
        return;
    }

    ds_queryCondition.set("gubun", "A"); // 협력업체 가용차량 등록

    ds_equipNonUseList.setJSON([]);
    $c.sbm.execute(sbm_retrieve);
};

//-------------------------------------------------------------------------
// 전일 등록 차량 불러오기 조회 
//-------------------------------------------------------------------------
scwin.f_retrievePrecedingSavedVehicles = async function () {
    let ret = await $c.gus.cfValidate([tbl_searchCond]);
    if (!ret) {
        return;
    }

    if (acb_con_logisticsBranch.getValue() == "") {
        $c.gus.cfAlertMsg(MSG_CM_ERR_056, ["계약점소"]); //선택된 @이(가) 없습니다.
        return;
    }

    scwin.searchFlag = 0;
    ds_queryCondition.set("gubun", "P"); // 전일등록 차량 불러오기 구분값 (P: Preceding)

    ds_equipPrecedingSaveList.setJSON([]);
    $c.sbm.execute(sbm_retrieve3);
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    //if (ds_equipUseHistory.getModifiedIndex().length == 0) {
    if (ds_equipUseHistory.getModifiedJSON().length == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["협력업체 가용차량"]); //변경된 정보가 없습니다.
        return;
    }

    // Grid의 필수 입력 항목에 대해서 Check 한다.
    let ret = await $c.gus.cfValidate([gr_subWorkImplement])
    if (!ret) return;

    ret = await scwin.f_CheckSaveOverLap()
    if (!ret) return;

    for (i = 0; i < ds_equipUseHistory.getRowCount(); i++) {
        ds_equipUseHistory.setCellData(i, "usblDt", ica_con_usblDt.getValue());
    }

    for (i = 0; i < ds_equipUseHistory.getRowCount(); i++) {
        if (ds_equipUseHistory.getCellData(i, "usblHh") < 10) {
            if (ds_equipUseHistory.getCellData(i, "usblHh").length != 2) {
                $c.win.alert(i + " 번째 행의 가용시간은 0" + ds_equipUseHistory.getCellData(i, "usblHh") + " 형식으로 입력하세요.");
                return;
            }
        }

        if (parseInt(ds_equipUseHistory.getCellData(i, 'usblHh')) > 24) {
            $c.win.alert(i + " 번째 행의 가용시간은 25보다 작은 수를 입력하세요.");
            return;
        }
    }

    ret = await $c.win.confirm("저장하시겠습니까?");
    if (ret) {
        $c.sbm.execute(sbm_save);
    }
}

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function (inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
}

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {

    switch (disGubun) {
        case 1:
            pWhere = "01,";
            // 조회 협력업체조회 pSelectID, pCode, pName, pWinCloseTF, pDispCnt, pTitle, pWidth, pHidden, pWhere, pW, pH, pTop, pLeft
            udc_clntNo.setSelectId("retrieveCarKindClntInfo");
            udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc // 콜백 함수
                , ed_clntNo.getValue().trim()
                , ed_clntNm.getValue()
                , 'T'
                , '5'
                , null
                , null
                , null
                , pWhere
                , '440'
                , '500'
                , null
                , null
            );
    }
}

