scwin.ln_RightMove = function () {debugger;
    // 선택된 ROWS index를 배열로 가져오기
    var focusedRows = gr_subWorkImplement.getAllFocusedRowIndex()

    for (var i = 0; i < focusedRows.length; i++) {
        var originRow = focusedRows[i];
        var newRow = ds_equipNonUseList.insertRow();
        ds_equipNonUseList.setRowPosition(newRow);
