        ds_equipNonUseList.setCellData(newRow, 'lobranNm', ds_equipUseHistory.getCellData(originRow, 'lobranNm'));
        ds_equipNonUseList.setCellData(newRow, 'eqDrvNm', ds_equipUseHistory.getCellData(originRow, 'eqDrvNm'));
        ds_equipNonUseList.setCellData(newRow, 'mp', ds_equipUseHistory.getCellData(originRow, 'mp'));
        ds_equipNonUseList.setCellData(newRow, 'vehclShortCd', ds_equipUseHistory.getCellData(originRow, 'vehclShortCd'));
        ds_equipNonUseList.setCellData(newRow, 'eqClsCd', ds_equipUseHistory.getCellData(originRow, 'eqClsCd'));
        ds_equipNonUseList.setCellData(newRow, 'eqClsNm', ds_equipUseHistory.getCellData(originRow, 'eqClsNm'));
        ds_equipNonUseList.setCellData(newRow, 'currSts', ds_equipUseHistory.getCellData(originRow, 'currSts'));
        ds_equipNonUseList.setCellData(newRow, 'eqNrm', ds_equipUseHistory.getCellData(originRow, 'eqNrmCd'));
        ds_equipNonUseList.setCellData(newRow, 'eqNrmNm', ds_equipUseHistory.getCellData(originRow, 'eqNrmNm'));
        ds_equipNonUseList.setCellData(newRow, 'wrkIndictNo', ds_equipUseHistory.getCellData(originRow, 'wrkIndictNo'));
