        ds_equipNonUseList.setCellData(newRow, 'chassisKndCd', ds_equipUseHistory.getCellData(originRow, 'chassisKndCd'));
        ds_equipNonUseList.setCellData(newRow, 'cmpstcrgDistrictCd', ds_equipUseHistory.getCellData(originRow, 'cmpstcrgDistrictCd'));
        ds_equipNonUseList.setCellData(newRow, 'cmpstcrgDistrictCd2', ds_equipUseHistory.getCellData(originRow, 'cmpstcrgDistrictCd2'));
        ds_equipNonUseList.setCellData(newRow, 'cargoClsCd', ds_equipUseHistory.getCellData(originRow, 'cargoClsCd'));
        ds_equipNonUseList.setCellData(newRow, 'kcgCd1', ds_equipUseHistory.getCellData(originRow, 'kcgCd1'));
        ds_equipNonUseList.setCellData(newRow, 'kcgCd2', ds_equipUseHistory.getCellData(originRow, 'kcgCd2'));
        ds_equipNonUseList.setCellData(newRow, 'kcgNm1', ds_equipUseHistory.getCellData(originRow, 'kcgNm1'));
        ds_equipNonUseList.setCellData(newRow, 'kcgNm2', ds_equipUseHistory.getCellData(originRow, 'kcgNm2'));
        ds_equipNonUseList.setCellData(newRow, 'nonusblStDtm', ds_equipUseHistory.getCellData(originRow, 'nonusblStDtm'));
