//-------------------------------------------------------------------------
// 엑셀 다운로드
//------------------------------------------------------------------------- 
scwin.f_runExcel = async function (varGrNm) {
    var totCnt = 0;
    var sheetTitle = "";

    if (varGrNm == "gr_workImplement") {
        totCnt = gr_workImplement.getTotalRow();
        sheetTitle = '가용차량현황';
    } else {
        totCnt = gr_subWorkImplement.getTotalRow();
        sheetTitle = '가용차량등록';
    }

    if (totCnt != "0") {
        let cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");

        if (cfrm) {
            const options = {
                fileName: sheetTitle + ".xlsx" //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
                , sheetName: sheetTitle //엑셀내 시트명 지정필요시
            };

            const infoArr = [];
            if (varGrNm == "gr_workImplement") {
                $c.data.downloadGridViewExcel(gr_workImplement, options, infoArr);
            } else {
                $c.data.downloadGridViewExcel(gr_subWorkImplement, options, infoArr);
            }
        }
    } else {
        $c.gus.cfAlertMsg(MSG_CM_WRN_002);
    }

}

//-------------------------------------------------------------------------
// 화종구분 팝업
//-------------------------------------------------------------------------
scwin.f_PopUpHwajongInfo = function (row, colid) {

    if(scwin._oncelldatachange) {
        scwin._oncelldatachange = false;
        return;
    }

    if (colid == "kcgNm1" || colid == "kcgNm2") {
        if (colid == "kcgNm1") {
            //화종구분1 검색
            udc_comCode1.setSelectId("retrieveHwajongInfo");
            udc_comCode1.cfCommonPopUp(scwin.udc_kcgNm1_callBackFunc
                , ''
                , ds_equipUseHistory.getCellData(row, 'kcgNm1')
                , 'T'
                , '5'
                , null
                , null
                , null
                , '2'
                , '440'
                , '500'
                , null
                , null
            );
        } else if (colid == "kcgNm2") {
            //화종구분2 검색
            udc_comCode1.setSelectId("retrieveHwajongInfo");
            udc_comCode1.cfCommonPopUp(scwin.udc_kcgNm2_callBackFunc
                , ''
                , ds_equipUseHistory.getCellData(row, 'kcgNm2')
                , 'T'
                , '5'
                , null
                , null
                , null
                , '2'
                , '440'
                , '500'
                , null
                , null
            );
        }
    }
};

