scwin.f_FieldClear = function () {

    if (scwin.userClsCd != "01") { //사용자가 협력업체 일때
        $c.gus.cfInitObjects(tbl_searchCond, [ica_con_usblDt, ed_clntNo, ed_clntNm]);
    } else {
        $c.gus.cfInitObjects(tbl_searchCond, [ica_con_usblDt]);
    }

}

//-------------------------------------------------------------------------
// 중복 Check
//-------------------------------------------------------------------------
scwin.f_CheckSaveOverLap = async function () {
    var rowCnt = ds_equipUseHistory.getRowCount();

    for (i = 0; i < rowCnt; i++) {
        var vehclNo = ds_equipUseHistory.getCellData(i, "vehclNo");
        var lobranCd = ds_equipUseHistory.getCellData(i, "lobranCd");

        for (j = i + 1; j < rowCnt; j++) {
            var vehclNoNext = ds_equipUseHistory.getCellData(j, "vehclNo");
            var lobranCdNext = ds_equipUseHistory.getCellData(j, "lobranCd");

            if (vehclNo == vehclNoNext && lobranCd == lobranCdNext) {
                if (vehclNo == vehclNoNext) {
                    $c.gus.cfAlertMsg(j + "번째 행의 차량번호가 중복됩니다.");
                    ds_equipUseHistory.deleteRow(j);
                    return false;
                }
                if (lobranCd == lobranCdNext) {
                    $c.gus.cfAlertMsg(j + "번째 행의 요청점소가 중복됩니다.");
                    ds_equipUseHistory.deleteRow(j);
                    return false;
                }
            }

        } // for

    } // for

    return true;
}

//-------------------------------------------------------------------------
// 장비리스트조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_equipNonUseList.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
    } else {
        gr_workImplement.setFocusedCell(0, 0, false); //edit : true
    }
    $c.sbm.execute(sbm_retrieve2);
    tbx_totalRows1.setValue(ds_equipNonUseList.getRowCount());

    // if ($c.gus.cfCheckCreateFlag() == true) { //사용안해도 될듯
    //     $c.gus.cfTurnCreateFlag(false);
    // }
};

//-------------------------------------------------------------------------
// 협력업체가용차량리스트조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve2_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_equipUseHistory.getRowCount() > 0) {        
        gr_subWorkImplement.setFocusedCell(0, 0, false); //edit : true
    }

    tbx_totalRows2.setValue(ds_equipUseHistory.getRowCount());
};

//-------------------------------------------------------------------------
// 협력업체 전일 등록 차량리스트조회 submitdone
//-------------------------------------------------------------------------
scwin.sbm_retrieve3_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    if (ds_equipPrecedingSaveList.getRowCount() == 0) {
        $c.gus.cfAlertMsg(MSG_CM_ERR_003);
        return;
    }
    //var totCnt = parseInt(ds_equipUseHistory.getRowCount()) + parseInt(ds_equipPrecedingSaveList.getRowCount());
    var totCnt = parseInt(ds_equipUseHistory.getRowCount());
    //ds_equipUseHistory.ImportData(ds_equipPrecedingSaveList.ExportData(1, rowCnt, true));
    //$c.gus.copy(ds_equipPrecedingSaveList, ds_equipUseHistory, false, "rowFrom=0,rowCnt="+totCnt); // 데이터셋 복사    
    //$c.gus.cfCopyDataSet(ds_equipPrecedingSaveList, ds_equipUseHistory, "rowFrom=0,rowCnt=" + totCnt); // 데이터셋 복사

    ds_equipUseHistory.setJSON(ds_equipPrecedingSaveList.getAllJSON(), true);
    ds_equipUseHistory.modifyRangeStatus(totCnt, ds_equipUseHistory.getRowCount()-1, "C"); // 전일등록 차량만 insert 상태로 수정

    if (totCnt == 0) {
        gr_subWorkImplement.setFocusedCell(0, 0, false); //edit : true
    }

    tbx_totalRows2.setValue(ds_equipUseHistory.getRowCount());
};

//-------------------------------------------------------------------------
// 저장 submitdone
//-------------------------------------------------------------------------
scwin.sbm_save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.gus.cfAlertMsg(MSG_CM_INF_001); // 성공적으로 저장하였습니다.

    scwin.f_Retrieve();
};

