//-------------------------------------------------------------------------
scwin.udc_kcgNm1_callBackFunc = function (ret) {
    ds_equipUseHistory.setEventPause("oncelldatachange", true);
    if (ret != null) {
        ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgCd1', ret[0]); //화종코드
        ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgNm1', ret[1]); //화종명명

        if (ds_equipUseHistory.getCellData(ds_equipUseHistory.getRowPosition(), 'kcgNm1') == "undefined") {
            ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgCd1', "");
            ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgNm1', "");
        }
    } else {
        ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgCd1', "");
        ds_equipUseHistory.setCellData(ds_equipUseHistory.getRowPosition(), 'kcgNm1', "");
    }
    ds_equipUseHistory.setEventPause("oncelldatachange", false);
};

