//-------------------------------------------------------------------------
scwin.gr_subWorkImplement_onbeforeedit = function (rowIndex, columnIndex, value) {
    if (columnIndex == 3) { //화물구분(cargoClsCd)
        ds_equipUseHistory.setCellData(rowIndex, "cmpstcrgDistrictCd", "");
        ds_equipUseHistory.setCellData(rowIndex, "cmpstcrgDistrictCd2", "");
    }

    if (columnIndex == 4 || columnIndex == 5) { //4:cmpstcrgDistrictCd, 5:cmpstcrgDistrictCd2
        var v_val = '';
        if (ds_equipUseHistory.getCellData(ds_equipUseHistory.getRowPosition(), 'cargoClsCd') == "B")
            v_val = 'BWK';
        else
            v_val = 'CMP';

        dlt_district.removeColumnFilterAll();
        $c.data.dataListFilter(dlt_district, "upperDistrictCd=='" + v_val + "'");

        // dlt_district2.removeColumnFilterAll(); //복화권역은 같은 데이터기 때문에 하나만 사용해도됨
        // $c.data.dataListFilter(dlt_district2, "upperDistrictCd=='" + v_val + "'");
    }
};

