// ASIS : gr_subWorkImplement OnExit(row,colid,olddata)
//-------------------------------------------------------------------------
scwin.ds_equipUseHistory_oncelldatachange = function (info) {
    if (info.newValue == info.oldValue) {
        return;
    } else {
        scwin._oncelldatachange = true;
        if (info.colID == "kcgNm1") {
            //화종구분1 검색
            udc_comCode1.setSelectId("retrieveHwajongInfo");
            udc_comCode1.cfCommonPopUp(scwin.udc_kcgNm1_callBackFunc, '', ds_equipUseHistory.getCellData(info.rowIndex, 'kcgNm1'), 'T', '5', null, null, null, '2', '440', '500', null, null);
        } else if (info.colID == "kcgNm2") {
            //화종구분2 검색
            udc_comCode1.setSelectId("retrieveHwajongInfo");
            udc_comCode1.cfCommonPopUp(scwin.udc_kcgNm2_callBackFunc, '', ds_equipUseHistory.getCellData(info.rowIndex, 'kcgNm2'), 'T', '5', null, null, null, '2', '440', '500', null, null);
        }
    }
};

